// 検査周期 vs 限度 の判定ロジック。
// 走行キロ・経過日数 のうち「限度に最も肉薄している側」を採用し、
// 余裕(0–1) と flag(余裕あり/期限間近/超過) を返す。
import {
  type Formation,
  INSPECTION_CYCLE,
  daysUntil,
} from "./data";

export type CycleFlag = "ok" | "due-soon" | "overdue";

export interface CycleReading {
  /** 採用した判定軸 */
  basis: "km" | "days";
  /** 限度に対する消化率（0–1超で超過） */
  fraction: number;
  /** 現在値（採用軸） */
  current: number;
  /** 限度値（採用軸） */
  limit: number;
  flag: CycleFlag;
  /** 走行キロ側の読み（限度があるときのみ） */
  km?: { current: number; limit: number; fraction: number };
  /** 経過日数→残日数（期限日基準） */
  days: { until: number; limit?: number };
}

/** due-soon の閾値：限度の80%以上で「期限間近」、100%超で「超過」 */
const WARN = 0.8;

export function readCycle(f: Formation): CycleReading {
  const cycle = INSPECTION_CYCLE[f.nextKind];
  const until = daysUntil(f.nextDueDate);

  // 走行キロ軸（重要部・全般のみ limitKm を持つ）
  let km: CycleReading["km"];
  if (cycle.limitKm != null) {
    const base = f.lastKindKm ?? 0;
    const used = Math.max(0, f.odometerKm - base);
    km = { current: used, limit: cycle.limitKm, fraction: used / cycle.limitKm };
  }

  // 日数軸：限度日数に対する消化率を残日数から逆算
  const limitDays = cycle.limitDays;
  let daysFraction = 0;
  if (limitDays != null) {
    daysFraction = (limitDays - until) / limitDays;
  } else {
    // 限度日数なし（理論上ないが安全側）：残日数で簡易判定
    daysFraction = until <= 0 ? 1.1 : until <= 5 ? 0.85 : 0.4;
  }

  // 限度に最も肉薄している軸を採用
  const kmFraction = km?.fraction ?? 0;
  const basis: "km" | "days" = kmFraction >= daysFraction ? "km" : "days";

  const fraction = Math.max(kmFraction, daysFraction);
  const flag: CycleFlag =
    fraction >= 1 ? "overdue" : fraction >= WARN ? "due-soon" : "ok";

  return {
    basis,
    fraction,
    current: basis === "km" && km ? km.current : limitDays != null ? limitDays - until : until,
    limit: basis === "km" && km ? km.limit : limitDays ?? 0,
    flag,
    km,
    days: { until, limit: limitDays },
  };
}

