/** 日数差（today を基準に dueDate までの残日数。負なら超過）— SSR安全に文字列計算。 */
export function daysUntil(dueDate: string, today: string = TODAY): number {
  const toUtc = (s: string) => {
    const [y, m, d] = s.split("-").map(Number);
    return Date.UTC(y, m - 1, d);
  };
  return Math.round((toUtc(dueDate) - toUtc(today)) / 86_400_000);
}

"use client";

import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  MetadataList,
  Timeline,
  TimelineItem,
  TimelineTitle,
  TimelineDescription,
  TimelineTime,
  LineChart,
  Badge,
  Separator,
  Meter,
  formatNumber,
} from "@gunjo/ui";

import {
  type Formation,
  FLEET_STATUS_LABEL,
  INSPECTION_KIND_LABEL,
  FORMATION_DETAILS,
} from "./data";
import { readCycle, CYCLE_FLAG_LABEL } from "./cycle";

const DEFECT_TONE: Record<string, "warning" | "info" | "success"> = {
  未対応: "warning",
  対応中: "info",
  完了: "success",
};

export function FormationDetailSheet({
  formation,
  open,
  onOpenChange,
}: {
  formation: Formation | null;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}) {
  if (!formation) return null;
  const detail = FORMATION_DETAILS[formation.id];
  const cycle = readCycle(formation);

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="right"
        closeLabel="閉じる"
        className="w-full overflow-y-auto sm:max-w-lg"
      >
        <SheetHeader>
          <SheetTitle>
            {formation.setNo}（{formation.series}・{formation.cars}両）
          </SheetTitle>
          <SheetDescription>
            {formation.depot}・状態 {FLEET_STATUS_LABEL[formation.status]}
          </SheetDescription>
        </SheetHeader>

        <div className="mt-4 flex flex-col gap-6">
          <section aria-label="次回検査">
            <h3 className="mb-2 text-sm font-semibold">次回検査予定</h3>
            <div className="rounded-lg border border-border p-3">
              <div className="mb-2 flex items-center gap-2">
                <Badge
                  variant={
                    cycle.flag === "overdue"
                      ? "destructive"
                      : cycle.flag === "due-soon"
                        ? "warning"
                        : "success"
                  }
                >
                  {CYCLE_FLAG_LABEL[cycle.flag]}
                </Badge>
                <span className="text-sm font-medium">
                  {INSPECTION_KIND_LABEL[formation.nextKind]}
                </span>
                <span className="ml-auto text-xs text-muted-foreground">
                  期限 {formation.nextDueDate}
                </span>
              </div>
              <Meter
                value={cycle.current}
                max={cycle.limit}
                label={`${INSPECTION_KIND_LABEL[formation.nextKind]} 周期の消化（${
                  cycle.basis === "km" ? "走行キロ" : "経過日数"
                }）`}
                unit={cycle.basis === "km" ? "km" : "日"}
                formatValue={
                  cycle.basis === "km" ? (n) => formatNumber(n) : undefined
                }
                thresholds={{ warning: 0.8, over: 1 }}
              />
            </div>
          </section>

          {detail ? (
            <>
              <section aria-label="走行キロ推移">
                <h3 className="mb-2 text-sm font-semibold">走行キロ推移（積算）</h3>
                <LineChart
                  variant="area"
                  showLabels
                  series={[
                    {
                      label: "積算走行キロ",
                      data: detail.kmTrend.map((p) => ({
                        label: p.month,
                        value: p.km,
                      })),
                    },
                  ]}
                  formatValue={(v) => `${formatNumber(v)}km`}
                />
              </section>

              <Separator />

              <section aria-label="検査履歴">
                <h3 className="mb-2 text-sm font-semibold">検査履歴</h3>
                <Timeline>
                  {detail.history.map((h, i) => (
                    <TimelineItem
                      key={i}
                      connector={i < detail.history.length - 1}
                      variant={i === 0 ? "active" : "default"}
                    >
                      <TimelineTime>{h.date}</TimelineTime>
                      <TimelineTitle>
                        {INSPECTION_KIND_LABEL[h.kind]}
                      </TimelineTitle>
                      <TimelineDescription>
                        {formatNumber(h.km)}km・{h.note}
                      </TimelineDescription>
                    </TimelineItem>
                  ))}
                </Timeline>
              </section>

              <Separator />

              <section aria-label="不具合履歴">
                <h3 className="mb-2 text-sm font-semibold">不具合履歴</h3>
                <ul className="flex flex-col gap-2">
                  {detail.defects.map((d, i) => (
                    <li
                      key={i}
                      className="flex items-center gap-2 rounded-md border border-border p-2 text-sm"
                    >
                      <Badge variant={DEFECT_TONE[d.status] === "warning" ? "warning" : DEFECT_TONE[d.status] === "info" ? "info" : "success"}>
                        {d.status}
                      </Badge>
                      <span className="font-medium">{d.car}</span>
                      <span className="text-muted-foreground">{d.symptom}</span>
                      <span className="ml-auto text-xs text-muted-foreground">
                        {d.date}
                      </span>
                    </li>
                  ))}
                </ul>
              </section>
            </>
          ) : (
            <MetadataList
              items={[
                { label: "走行キロ", value: `${formatNumber(formation.odometerKm)}km` },
                { label: "配置区", value: formation.depot },
                { label: "両数", value: `${formation.cars}両` },
                { label: "未対応 不具合", value: `${formation.openDefects}件` },
              ]}
            />
          )}
        </div>
      </SheetContent>
    </Sheet>
  );
}

