"use client";

import * as React from "react";
import type { ColumnDef } from "@gunjo/ui";
import {
  Container,
  StatGroup,
  DataTable,
  Badge,
  Meter,
  Gantt,
  ActionQueue,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Card,
  CardHeader,
  CardTitle,
  CardContent,
  Breadcrumb,
  Separator,
  formatNumber,
} from "@gunjo/ui";

import {
  type Formation,
  type FleetStatus,
  FLEET_STATUS_LABEL,
  INSPECTION_KIND_LABEL,
  FORMATIONS,
  SHOP_VISITS,
  ALERTS,
  TODAY,
} from "./data";
import { readCycle, CYCLE_FLAG_LABEL, type CycleFlag } from "./cycle";
import { FormationDetailSheet } from "./FormationDetailSheet";
import { InspectionRecordCard } from "./InspectionRecordCard";

const STATUS_BADGE: Record<FleetStatus, "default" | "success" | "info" | "warning" | "secondary" | "outline"> = {
  "in-service": "success",
  "in-shop": "info",
  awaiting: "warning",
  outshopping: "secondary",
  withdrawn: "outline",
};

const FLAG_BADGE: Record<CycleFlag, "success" | "warning" | "destructive"> = {
  ok: "success",
  "due-soon": "warning",
  overdue: "destructive",
};

const KIND_TONE: Record<
  string,
  "primary" | "info" | "success" | "warning" | "default"
> = {
  daily: "default",
  train: "default",
  monthly: "info",
  important: "warning",
  general: "primary",
};

function summarize() {
  const total = FORMATIONS.length;
  const inService = FORMATIONS.filter((f) => f.status === "in-service").length;
  const inShop = FORMATIONS.filter((f) => f.status === "in-shop").length;
  const awaiting = FORMATIONS.filter((f) => f.status === "awaiting").length;
  const dueSoon = FORMATIONS.filter((f) => {
    const c = readCycle(f).flag;
    return c === "due-soon" || c === "overdue";
  }).length;
  const defects = FORMATIONS.reduce((s, f) => s + f.openDefects, 0);
  return { total, inService, inShop, awaiting, dueSoon, defects };
}

export default function RailMaintenance() {
  const [selected, setSelected] = React.useState<Formation | null>(null);
  const [open, setOpen] = React.useState(false);

  const k = summarize();

  const openDetail = React.useCallback((f: Formation) => {
    setSelected(f);
    setOpen(true);
  }, []);

  const columns = React.useMemo<ColumnDef<Formation>[]>(
    () => [
      {
        accessorKey: "setNo",
        header: "編成",
        cell: ({ row }) => {
          const f = row.original;
          return (
            <div className="flex flex-col">
              <span className="font-medium">{f.setNo}</span>
              <span className="text-xs text-muted-foreground">
                {f.series}・{f.cars}両・{f.depot}
              </span>
            </div>
          );
        },
      },
      {
        accessorKey: "status",
        header: "状態",
        cell: ({ row }) => (
          <Badge variant={STATUS_BADGE[row.original.status]}>
            {FLEET_STATUS_LABEL[row.original.status]}
          </Badge>
        ),
      },
      {
        accessorKey: "odometerKm",
        header: "走行キロ",
        cell: ({ row }) => (
          <span className="tabular-nums">
            {formatNumber(row.original.odometerKm)}km
          </span>
        ),
      },
      {
        id: "nextKind",
        header: "次回検査",
        cell: ({ row }) => {
          const f = row.original;
          return (
            <div className="flex flex-col gap-0.5">
              <span className="text-sm">
                {INSPECTION_KIND_LABEL[f.nextKind]}
              </span>
              <span className="text-xs text-muted-foreground">
                期限 {f.nextDueDate}
              </span>
            </div>
          );
        },
      },
      {
        id: "cycle",
        header: "検査周期（残）",
        cell: ({ row }) => {
          const c = readCycle(row.original);
          return (
            <div className="flex min-w-[150px] flex-col gap-1">
              <div className="flex items-center gap-1.5">
                <Badge variant={FLAG_BADGE[c.flag]}>
                  {CYCLE_FLAG_LABEL[c.flag]}
                </Badge>
                <span className="text-xs text-muted-foreground">
                  {c.basis === "km"
                    ? `残 ${formatNumber(Math.max(0, c.limit - c.current))}km`
                    : `残 ${c.days.until}日`}
                </span>
              </div>
              <Meter
                size="inline"
                value={c.current}
                max={c.limit}
                thresholds={{ warning: 0.8, over: 1 }}
                label={`${row.original.setNo} ${INSPECTION_KIND_LABEL[row.original.nextKind]} 周期消化`}
                formatValue={
                  c.basis === "km" ? (n) => formatNumber(n) : undefined
                }
                unit={c.basis === "km" ? "km" : "日"}
              />
            </div>
          );
        },
      },
      {
        accessorKey: "openDefects",
        header: "不具合",
        cell: ({ row }) =>
          row.original.openDefects > 0 ? (
            <Badge variant="destructive">{row.original.openDefects}件</Badge>
          ) : (
            <span className="text-xs text-muted-foreground">—</span>
          ),
      },
    ],
    []
  );

  const ganttRows = FORMATIONS.filter((f) =>
    SHOP_VISITS.some((v) => v.formationId === f.id)
  ).map((f) => ({
    id: f.id,
    label: f.setNo,
    sublabel: `${f.series}・${f.cars}両`,
  }));

  const ganttItems = SHOP_VISITS.map((v) => ({
    id: v.id,
    rowId: v.formationId,
    start: v.inDate,
    end: v.outDate,
    label: INSPECTION_KIND_LABEL[v.kind],
    tone: (v.status === "in-progress"
      ? "info"
      : KIND_TONE[v.kind] === "primary"
        ? "primary"
        : KIND_TONE[v.kind] === "warning"
          ? "warning"
          : "default") as
      | "info"
      | "primary"
      | "warning"
      | "default",
    ariaLabel: `${INSPECTION_KIND_LABEL[v.kind]}・入場 ${v.inDate} 〜 出場 ${v.outDate}`,
  }));

  return (
    <Container size="2xl" className="py-6">
      <Breadcrumb
        className="mb-3"
        items={[
          { label: "車両所", href: "#" },
          { label: "緑山車両所 検修区", href: "#" },
          { label: "検査・保守管理" },
        ]}
      />

      <header className="mb-5">
        <h1 className="text-xl font-bold sm:text-2xl">検査・保守管理</h1>
        <p className="mt-1 text-sm text-muted-foreground">
          緑山車両所 検修区 — 保有編成の検査周期・入出場計画・不具合を一元管理（基準日 {TODAY}）
        </p>
      </header>

      {/* KPI ストリップ */}
      <StatGroup
        className="mb-6"
        cols={{ base: 2, md: 3, lg: 6 }}
        items={[
          { label: "在籍編成", value: `${k.total}本` },
          { label: "運用中", value: `${k.inService}本`, tone: "positive" },
          { label: "入場中", value: `${k.inShop}本` },
          { label: "検査待ち", value: `${k.awaiting}本` },
          {
            label: "検査期限間近・超過",
            value: `${k.dueSoon}本`,
            tone: "negative",
            hint: "期限間近＋超過",
          },
          {
            label: "未対応 不具合",
            value: `${k.defects}件`,
            tone: "negative",
          },
        ]}
      />

      <Tabs defaultValue="fleet" className="w-full">
        <TabsList className="mb-4 flex-wrap">
          <TabsTrigger value="fleet">編成一覧</TabsTrigger>
          <TabsTrigger value="schedule">検査計画</TabsTrigger>
          <TabsTrigger value="alerts">要対応</TabsTrigger>
          <TabsTrigger value="record">検査記録</TabsTrigger>
        </TabsList>

        {/* 編成一覧（保有車両） + 検査周期 vs 限度 */}
        <TabsContent value="fleet">
          <Card>
            <CardHeader>
              <CardTitle>編成一覧（保有車両）</CardTitle>
            </CardHeader>
            <CardContent>
              <DataTable
                columns={columns}
                data={FORMATIONS}
                filter={{ columnId: "setNo", placeholder: "編成番号で絞り込み" }}
                pageSize={10}
                onRowClick={openDetail}
                renderCard={(f) => {
                  const c = readCycle(f);
                  return (
                    <button
                      type="button"
                      onClick={() => openDetail(f)}
                      className="flex w-full flex-col gap-2 rounded-lg border border-border p-3 text-left"
                    >
                      <div className="flex items-center justify-between gap-2">
                        <span className="font-medium">{f.setNo}</span>
                        <Badge variant={STATUS_BADGE[f.status]}>
                          {FLEET_STATUS_LABEL[f.status]}
                        </Badge>
                      </div>
                      <span className="text-xs text-muted-foreground">
                        {f.series}・{f.cars}両・{f.depot}・
                        {formatNumber(f.odometerKm)}km
                      </span>
                      <div className="flex items-center gap-1.5">
                        <Badge variant={FLAG_BADGE[c.flag]}>
                          {CYCLE_FLAG_LABEL[c.flag]}
                        </Badge>
                        <span className="text-xs">
                          {INSPECTION_KIND_LABEL[f.nextKind]}・期限 {f.nextDueDate}
                        </span>
                      </div>
                      <Meter
                        size="inline"
                        value={c.current}
                        max={c.limit}
                        thresholds={{ warning: 0.8, over: 1 }}
                        label={`${f.setNo} 周期消化`}
                        formatValue={
                          c.basis === "km" ? (n) => formatNumber(n) : undefined
                        }
                        unit={c.basis === "km" ? "km" : "日"}
                      />
                    </button>
                  );
                }}
              />
              <p className="mt-3 text-xs text-muted-foreground">
                行をクリックすると編成の検査履歴・走行キロ推移・不具合履歴を表示します。
              </p>
            </CardContent>
          </Card>
        </TabsContent>

        {/* 検査計画（入出場スケジュール）— 編成 × 時間軸 */}
        <TabsContent value="schedule">
          <Card>
            <CardHeader>
              <CardTitle>検査計画（入出場スケジュール）</CardTitle>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <Gantt
                  label="検査計画 入出場スケジュール"
                  rows={ganttRows}
                  items={ganttItems}
                  startDate="2026-06-22"
                  endDate="2026-07-31"
                  today={TODAY}
                  rowLabelWidth={140}
                  dayWidth={20}
                  onSelectItem={(item) => {
                    const f = FORMATIONS.find((x) => x.id === item.rowId);
                    if (f) openDetail(f);
                  }}
                />
              </div>
              <div className="mt-3 flex flex-wrap gap-x-4 gap-y-1 text-xs text-muted-foreground">
                <span className="flex items-center gap-1">
                  <span className="inline-block h-3 w-3 rounded-sm border border-info-border bg-info-subtle" />
                  入場中
                </span>
                <span className="flex items-center gap-1">
                  <span className="inline-block h-3 w-3 rounded-sm border border-warning-border bg-warning-subtle" />
                  重要部検査
                </span>
                <span className="flex items-center gap-1">
                  <span className="inline-block h-3 w-3 rounded-sm border border-primary/40 bg-primary/15" />
                  全般検査
                </span>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        {/* 要対応アラート */}
        <TabsContent value="alerts">
          <Card>
            <CardHeader>
              <CardTitle>要対応アラート</CardTitle>
            </CardHeader>
            <CardContent>
              <ActionQueue
                items={ALERTS.map((a) => ({
                  id: a.id,
                  severity: a.severity,
                  kind: a.kind,
                  title: a.title,
                  detail: a.detail,
                  meta: a.meta,
                }))}
              />
            </CardContent>
          </Card>
        </TabsContent>

        {/* 検査記録（サインオフ） */}
        <TabsContent value="record">
          <InspectionRecordCard />
        </TabsContent>
      </Tabs>

      <Separator className="my-8" />

      <FormationDetailSheet
        formation={selected}
        open={open}
        onOpenChange={setOpen}
      />
    </Container>
  );
}
